#!/usr/bin/env tsx
/**
 * rknot-mesh-smoke — minimal end-to-end smoke for the multi-station
 * Monster Mesh built on rknot-backed fat-stations.
 *
 * Reads N station endpoints + their layer windows from env, constructs
 * the Pipeline directly (bypassing the Resonance Registry — fine for
 * a static known-fleet smoke), tokenizes a short prompt, runs the
 * forward+sample loop, prints the resulting token IDs + wall time.
 *
 * Use this to validate that:
 *   1. spawn-rknot-mesh.sh brought up healthy stations
 *   2. Pipeline can chain forward across them without crashing
 *   3. lm-head returns finite logits → first sampled token id
 *
 * If logits come back NaN/Inf, the smoke prints `argmax=u32::MAX`
 * (sampler returns sentinel) — that's a known signal the spectral
 * compression is too aggressive; re-encode with a less-lossy rknot
 * (Tracks A/B/C: --target-k 0.50, --bits-ffn 6, etc.).
 *
 * Env:
 *   MESH_STATION_URLS    comma-separated list of fat-station base URLs
 *                        (e.g. "http://host:8001,http://host:8002,...")
 *   MESH_LAYERS_PER      layers per station (default: 10)
 *   MESH_TOTAL_LAYERS    total transformer layers (default: 80 for L70B)
 *   MESH_HIDDEN_DIM      hidden dim of the model (default: 8192)
 *   MESH_VOCAB_SIZE      vocab size (default: 128256 for Llama-3)
 *   MESH_PROMPT_TOKENS   comma-separated u32 prompt token ids
 *                        (default: 1,450,7483,310,3444,338 — placeholder)
 *   MESH_MAX_TOKENS      tokens to generate (default: 4)
 *
 * Example (local single-host with 8 stations on ports 8001-8008): set
 * MESH_STATION_URLS to the comma-separated list of those URLs and run
 * with tsx (the exact one-liner kept out of this comment because TS
 * parser choked on shell escape sequences inside JSDoc).
 */

import { Station } from '../station';
import { Pipeline } from '../pipeline';

function envU32(name: string, fallback: number): number {
  const raw = process.env[name];
  if (!raw) return fallback;
  const n = Number.parseInt(raw, 10);
  if (!Number.isFinite(n) || n <= 0) {
    throw new Error(`${name}=${raw} is not a positive integer`);
  }
  return n;
}

function envU32List(name: string, fallback: number[]): number[] {
  const raw = process.env[name];
  if (!raw) return fallback;
  return raw.split(',').map((s) => {
    const n = Number.parseInt(s.trim(), 10);
    if (!Number.isFinite(n) || n < 0) {
      throw new Error(`${name}: bad token id '${s}'`);
    }
    return n;
  });
}

async function main(): Promise<void> {
  const urlsRaw = process.env.MESH_STATION_URLS;
  if (!urlsRaw) {
    console.error(
      'ERROR: MESH_STATION_URLS env required (comma-separated fat-station base URLs)',
    );
    process.exit(2);
  }
  const urls = urlsRaw.split(',').map((s) => s.trim()).filter(Boolean);
  if (urls.length === 0) {
    console.error('ERROR: MESH_STATION_URLS resolved to zero URLs');
    process.exit(2);
  }

  const layersPer = envU32('MESH_LAYERS_PER', 10);
  const totalLayers = envU32('MESH_TOTAL_LAYERS', 80);
  const hiddenDim = envU32('MESH_HIDDEN_DIM', 8192);
  const vocabSize = envU32('MESH_VOCAB_SIZE', 128256);
  const promptTokens = envU32List(
    'MESH_PROMPT_TOKENS',
    [1, 450, 7483, 310, 3444, 338],
  );
  const maxTokens = envU32('MESH_MAX_TOKENS', 4);

  console.error(
    `[rknot-mesh-smoke] ${urls.length} stations × ${layersPer} layers ` +
      `(covering ${totalLayers}); hidden=${hiddenDim} vocab=${vocabSize}`,
  );

  const stations = urls.map((endpoint, i) => {
    const startLayer = i * layersPer;
    const endLayer = Math.min(startLayer + layersPer, totalLayers);
    // One fat-station covering the full model is `--role both` on the wire;
    // leave `role` unset so embed + lm_head guards both accept the same host.
    const role: 'entry' | 'mid' | 'exit' | undefined =
      urls.length === 1
        ? undefined
        : i === 0
          ? 'entry'
          : i === urls.length - 1
            ? 'exit'
            : 'mid';
    console.error(
      `  [station ${i}] ${endpoint} layers=${startLayer}..${endLayer} role=${role ?? 'unset'}`,
    );
    return new Station({ endpoint, startLayer, endLayer, role });
  });

  const lastEnd = stations[stations.length - 1]?.endLayer;
  if (lastEnd !== totalLayers) {
    console.error(
      `WARN: last station endLayer=${lastEnd} != MESH_TOTAL_LAYERS=${totalLayers}; ` +
        `stations may not cover the full model`,
    );
  }

  // Health probe each station before any forward — fail fast on a
  // dead station rather than mid-prompt.
  console.error(`[rknot-mesh-smoke] probing /health on each station…`);
  for (const [i, url] of urls.entries()) {
    const t0 = performance.now();
    let res: Response;
    try {
      res = await fetch(`${url}/health`, {
        method: 'GET',
        signal: AbortSignal.timeout(10_000),
      });
    } catch (e) {
      console.error(`  station ${i} (${url}): unreachable — ${(e as Error).message}`);
      process.exit(1);
    }
    const ok = res.ok;
    const elapsed = (performance.now() - t0).toFixed(0);
    console.error(`  station ${i}: ${ok ? 'OK' : `HTTP ${res.status}`} (${elapsed}ms)`);
    if (!ok) process.exit(1);
  }

  const pipeline = new Pipeline({
    stations,
    hiddenDim,
    vocabSize,
  });

  console.error(
    `[rknot-mesh-smoke] forwarding ${promptTokens.length}-token prompt, generating ${maxTokens} new tokens…`,
  );
  const t0 = performance.now();

  // The exact generate() shape varies — wrap in try so the smoke
  // surfaces a clean error if the API has changed since this was written.
  let result: unknown;
  try {
    if (typeof pipeline.generate !== 'function') {
      throw new Error(
        'Pipeline.generate is not a function — smoke needs an update for the current Pipeline API',
      );
    }
    result = await pipeline.generate({
      promptTokens: Uint32Array.from(promptTokens),
      maxNewTokens: maxTokens,
    });
  } catch (e) {
    console.error(`ERROR during pipeline.generate: ${(e as Error).message}`);
    process.exit(1);
  }

  const wall = ((performance.now() - t0) / 1000).toFixed(2);
  console.error(`[rknot-mesh-smoke] done in ${wall}s`);
  const outTokens =
    result instanceof Uint32Array ? Array.from(result) : Array.from(result as Iterable<number>);
  console.log(JSON.stringify(outTokens, null, 2));
}

main().catch((e) => {
  console.error(`FATAL: ${(e as Error).stack ?? String(e)}`);
  process.exit(1);
});
